#include <bits/stdc++.h>
using namespace std;
struct boom{
    int x,y;
}b1[101],b2[101];
int main(){
    int n,m,a,b;
    cin>>n>>m>>a>>b;
    for(int i=1;i<=a;i++)cin>>b1[i].x>>b1[i].y>>b2[i].x>>b2[i].y;
    for(int i=1;i<=b;i++){
        int yx,yy;
        cin>>yx>>yy;
        int ans=0,w;
        for(int j=1;j<=a;j++){
            if(b1[j].x<=yx && b2[j].x>=yx && b1[j].y<=yy && b2[j].y>=yy){
                ans++;
                w=j;
            }
        }
        //cout<<ans<<' '<<w<<endl; 
        if(ans==0)cout<<"N"<<endl;
        else cout<<"Y "<<ans<<' '<<w<<endl;
    }
    return 0;
}
